@page "/shipments"
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipment Management</h1>

<div class="mb-3">
    <label for="statusFilter" class="form-label">Filter by Status:</label>
    <select id="statusFilter" class="form-select w-auto d-inline-block" @bind="statusFilter" @bind:after="ApplyFilter">
        <option value="All">All</option>
        <option value="Pending">Pending</option>
        <option value="InTransit">InTransit</option>
        <option value="Delivered">Delivered</option>
        <option value="Delayed">Delayed</option>
    </select>
</div>

@if (filteredShipments is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Status</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Update Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in filteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Status</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" value="@shipment.Status"
                            @onchange="e => UpdateStatus(shipment, e.Value?.ToString())">
                            <option value="Pending">Pending</option>
                            <option value="InTransit">InTransit</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? allShipments;
    private List<Shipment>? filteredShipments;
    private string statusFilter = "All";

    protected override async Task OnInitializedAsync()
    {
        allShipments = await ShipmentService.GetAllShipmentsAsync();
        ApplyFilter();
    }

    private void ApplyFilter()
    {
        filteredShipments = statusFilter == "All"
            ? allShipments
            : allShipments?.Where(s => s.Status == statusFilter).ToList();
    }

    private async Task UpdateStatus(Shipment shipment, string? newStatus)
    {
        if (string.IsNullOrEmpty(newStatus) || newStatus == shipment.Status) return;
        await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
        ApplyFilter();
    }
}

@page "/track"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="mb-3">
    <label for="trackingInput" class="form-label">Tracking Number:</label>
    <div class="input-group w-auto">
        <input id="trackingInput" type="text" class="form-control" style="max-width: 300px;"
               @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
        <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
    </div>
</div>

@if (searched)
{
    @if (shipment is not null)
    {
        <div class="card mt-3" style="max-width: 500px;">
            <div class="card-body">
                <h5 class="card-title">Shipment @shipment.TrackingNumber</h5>
                <ul class="list-group list-group-flush">
                    <li class="list-group-item"><strong>Status:</strong> @shipment.Status</li>
                    <li class="list-group-item"><strong>Origin:</strong> @shipment.Origin</li>
                    <li class="list-group-item"><strong>Destination:</strong> @shipment.Destination</li>
                    <li class="list-group-item"><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "N/A")</li>
                </ul>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning mt-3" style="max-width: 500px;">
            No shipment found with tracking number "<strong>@searchedNumber</strong>". Please check the number and try again.
        </div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        searched = true;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }
}

