 @page "/shipments"
 @attribute [Authorize(Roles = "Dispatcher")]
 @inject IShipmentService ShipmentService

 <PageTitle>Shipments</PageTitle>

 <h1>Shipment Management</h1>

 <div class="mb-3">
     <label for="statusFilter" class="form-label">Filter by Status:</label>
     <select id="statusFilter" class="form-select w-auto d-inline-block" @bind="statusFilter" @bind:after="ApplyFilter">
         <option value="All">All</option>
         <option value="Pending">Pending</option>
         <option value="InTransit">InTransit</option>
         <option value="Delivered">Delivered</option>
         <option value="Delayed">Delayed</option>
     </select>
 </div>

 @if (filteredShipments is null)
 {
     <p><em>Loading...</em></p>
 }
 else
 {
     <table class="table table-striped">
         <thead>
             <tr>
                 <th>Tracking #</th>
                 <th>Status</th>
                 <th>Origin</th>
                 <th>Destination</th>
                 <th>Est. Delivery</th>
                 <th>Customer</th>
                 <th>Update Status</th>
             </tr>
